const input=$json.body??$json;
for(const field of ['client_id','source_event_id','workflow_name','template_key','template_version','field_values','output_format']) if(input[field]===undefined||input[field]===null||input[field]==='') throw new Error(`Missing required field: ${field}`);
const values=input.field_values; if(typeof values!=='object'||Array.isArray(values)) throw new Error('field_values must be an object');
for(const field of (input.required_fields??[])) if(values[field]===undefined||values[field]===null||values[field]==='') throw new Error(`Missing required document field: ${field}`);
const failedConditions=(input.conditions??[]).filter((rule)=>rule.operator==='equals' && values[rule.field]!==rule.value);
if(failedConditions.length) throw new Error('Document conditions were not satisfied');
const eventId=`${input.client_id}:document_generation:${input.source_event_id}`;
return [{json:{...input,event_id:eventId,feature_type:'custom_business_solutions',workflow_steps:[{step_key:'validate_request',step_name:'Validate document request',status:'success'},{step_key:'evaluate_conditions',step_name:'Evaluate document conditions',status:'success'}]}}];
